#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using System.Linq;
using MukioI18n;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;
using UnityEngine;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.resolution)]
    public class ResolutionOptionDropdown : OptionDropdownDefinition
    {
        public ResolutionOptionDropdown(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return !Global.Game.IsMobile();
        }

        public override void FillItems(IOptionContext context, List<string> items)
        {
            var resolutions = Screen.resolutions;
            var currentResolution = new Resolution()
            {
                width = Screen.width,
                height = Screen.height,
                refreshRateRatio = Screen.currentResolution.refreshRateRatio
            };
            Resolution[] values;
            if (!resolutions.Any(r => CompareResolution(r, currentResolution)))
            {
                values = new Resolution[resolutions.Length + 1];
                for (int i = 0; i < resolutions.Length; i++)
                {
                    values[i] = resolutions[i];
                }
                values[values.Length - 1] = currentResolution;
            }
            else
            {
                values = resolutions;
            }
            var texts = values.Select(v => GetResolutionName(v));
            items.AddRange(texts);
        }

        public override int GetValue(IOptionContext context)
        {
            var resolutions = Screen.resolutions;
            var currentResolution = new Resolution()
            {
                width = Screen.width,
                height = Screen.height,
                refreshRateRatio = Screen.currentResolution.refreshRateRatio
            };
            var index = Array.FindIndex(resolutions, r => CompareResolution(r, currentResolution));
            if (index < 0)
            {
                index = resolutions.Length;
            }
            return index;
        }

        public override void OnValueChanged(IOptionContext context, int index)
        {
            var resolutions = Screen.resolutions;
            if (index >= resolutions.Length)
                return;
            var resolution = resolutions[index];
            Screen.SetResolution(resolution.width, resolution.height, Screen.fullScreenMode, resolution.refreshRateRatio);
        }
        public static bool CompareResolution(Resolution res1, Resolution res2)
        {
            if (res1.width != res2.width || res1.height != res2.height)
                return false;
            if (res1.refreshRateRatio.CompareTo(res2.refreshRateRatio) != 0)
                return false;
            return true;
        }
        public static string GetResolutionName(Resolution resolution)
        {
            return Global.Localization.GetText(RESOLUTION_NAME, resolution.width, resolution.height, resolution.refreshRateRatio);
        }
        [TranslateMsg("分辨率名，{0}为宽，{1}为高,{2}为刷新率")]
        public const string RESOLUTION_NAME = "{0}x{1} @{2}Hz";
    }
}
